import subprocess, re, sys

# Audit script: find pub items without doc comments in src/
def audit_dir(dirpath):
    results = []
    for root, dirs, files in __import__('os').walk(dirpath):
        for fname in sorted(files):
            if not fname.endswith('.rs'):
                continue
            fpath = __import__('os.path').join(root, fname)
            with open(fpath) as f:
                lines = f.readlines()
