31	pub struct TrayHandle {
32	    /// Set to true by the tray "Open Config" action; cleared by the eframe loop.
33	    pub open_window: Arc<AtomicBool>,
34	    _thread: std::thread::JoinHandle<()>,
35	}
36	
37	impl TrayHandle {
38	    /// Spawn the tray on a dedicated tokio thread. Returns immediately.
39	    /// Returns `None` if the D-Bus session bus is not available (e.g. headless CI).
40	    pub fn spawn() -> Option<Self> {
41	        let open_window = Arc::new(AtomicBool::new(false));
42	        let open_window_clone = Arc::clone(&open_window);
43	
44	        let (tx, rx) = std::sync::mpsc::channel::<Result<(), String>>();
45	
46	        let thread = std::thread::Builder::new()
47	            .name("tray-tokio".into())
48	            .spawn(move || {
49	                let rt = match tokio::runtime::Builder::new_current_thread()
50	                    .enable_all()
51	                    .build()
52	                {
53	                    Ok(rt) => rt,
54	                    Err(e) => {
55	                        let _ = tx.send(Err(format!("tokio runtime build failed: {e}")));
56	                        return;
57	                    }
58	                };
59	
60	                rt.block_on(async move {
61	                    let tray = VibeTray {
62	                        open_window: Arc::clone(&open_window_clone),
63	                        state: Arc::new(Mutex::new(TrayState::default())),
64	                    };
65	                    let state_ref = Arc::clone(&tray.state);
66	
67	                    match tray.spawn().await {
68	                        Ok(handle) => {
69	                            let _ = tx.send(Ok(()));
70	
71	                            // Spawn the poll loop inside the same tokio runtime.
72	                            let poll_handle = handle.clone();
73	                            tokio::spawn(async move {
74	                                loop {
75	                                    tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
76	
77	                                    let status = query_status();
78	                                    let new_daemon_state = status.as_ref().map(|s| s.state.clone());
79	                                    let new_active_profile = status.and_then(|s| s.active_profile);
80	                                    // Read profile list from disk on each tick — cheap stat, no daemon needed.
81	                                    let new_profiles = load_profiles();
82	
83	                                    // Only push a D-Bus update when the visible state actually changed.
84	                                    let changed = {
85	                                        let s = state_ref.lock().await;
86	                                        s.daemon_state != new_daemon_state
87	                                            || s.active_profile != new_active_profile
88	                                            || s.profiles != new_profiles
89	                                    };
90	
91	                                    if changed {
92	                                        poll_handle
93	                                            .update(|tray: &mut VibeTray| {
94	                                                if let Ok(mut s) = tray.state.try_lock() {
95	                                                    s.daemon_state = new_daemon_state.clone();
96	                                                    s.active_profile = new_active_profile.clone();
97	                                                    s.profiles = new_profiles.clone();
98	                                                }
99	                                            })
100	                                            .await;
101	                                    }
102	                                }
103	                            });
104	
105	                            std::future::pending::<()>().await;
106	                        }
107	                        Err(e) => {
108	                            let _ = tx.send(Err(format!("tray spawn failed: {e}")));
109	                        }
110	                    }
111	                });
112	            })
113	            .ok()?;
114	
115	        match rx.recv() {
116	            Ok(Ok(())) => Some(TrayHandle {
117	                open_window,
118	                _thread: thread,
119	            }),
120	            Ok(Err(e)) => {
121	                tracing::warn!(reason = %e, "System tray unavailable");
122	                None
123	            }
124	            Err(_) => None,
125	        }
126	    }
127	
128	    /// Returns true (and resets the flag) if the tray requested the window to open.
129	    pub fn take_open_request(&self) -> bool {
130	        self.open_window.swap(false, Ordering::AcqRel)
131	    }
132	}
