181	
182	    fn menu(&self) -> Vec<MenuItem<Self>> {
183	        let state = self.current_state();
184	        let is_muted = matches!(state.daemon_state, Some(DaemonState::Muted));
185	        let daemon_running = state.daemon_state.is_some();
186	
187	        let open_flag = Arc::clone(&self.open_window);
188	
189	        let mut items: Vec<MenuItem<Self>> = Vec::new();
190	
191	        items.push(
192	            StandardItem {
193	                label: "Open Config".into(),
194	                icon_name: "preferences-system".into(),
195	                activate: Box::new(move |_this: &mut Self| {
196	                    open_flag.store(true, Ordering::Release);
197	                }),
198	                ..Default::default()
199	            }
200	            .into(),
201	        );
202	
203	        items.push(MenuItem::Separator);
204	
205	        if daemon_running {
206	            let mute_label = if is_muted { "Unmute" } else { "Mute" };
207	            let mute_icon = if is_muted {
208	                "audio-input-microphone"
209	            } else {
210	                "audio-input-microphone-muted"
211	            };
212	            items.push(
213	                StandardItem {
214	                    label: mute_label.into(),
215	                    icon_name: mute_icon.into(),
216	                    activate: Box::new(move |_this: &mut Self| {
217	                        let cmd = if is_muted {
218	                            ControlRequest::Unmute
219	                        } else {
220	                            ControlRequest::Mute
221	                        };
222	                        // Fire-and-forget on a fresh thread — ksni callbacks must not block.
223	                        std::thread::spawn(move || {
224	                            let _ = send_command(cmd);
225	                        });
226	                    }),
227	                    ..Default::default()
228	                }
229	                .into(),
230	            );
231	            items.push(MenuItem::Separator);
232	        }
233	
234	        // Profile switcher submenu — always shown, disabled when daemon is not running.
235	        let profile_submenu: Vec<MenuItem<Self>> = state
236	            .profiles
237	            .iter()
238	            .map(|name| {
239	                let is_active = state.active_profile.as_deref() == Some(name.as_str());
240	                let name_clone = name.clone();
241	                CheckmarkItem {
242	                    label: name.clone(),
243	                    checked: is_active,
244	                    enabled: daemon_running,
245	                    activate: Box::new(move |_this: &mut Self| {
246	                        let req = ControlRequest::SwitchProfile {
247	                            name: name_clone.clone(),
248	                        };
249	                        std::thread::spawn(move || {
250	                            let _ = send_command(req);
251	                        });
252	                    }),
253	                    ..Default::default()
254	                }
255	                .into()
256	            })
257	            .collect();
258	
259	        items.push(
260	            SubMenu {
261	                label: "Profiles".into(),
262	                icon_name: "folder".into(),
263	                enabled: !state.profiles.is_empty(),
264	                submenu: profile_submenu,
265	                ..Default::default()
266	            }
267	            .into(),
268	        );
269	
270	        items.push(MenuItem::Separator);
271	
272	        items.push(
273	            StandardItem {
274	                label: "Quit".into(),
275	                icon_name: "application-exit".into(),
276	                activate: Box::new(|_| std::process::exit(0)),
277	                ..Default::default()
278	            }
279	            .into(),
280	        );
281	
282	        items
283	    }
284	}
