104	    /// Shared state for the PTT key capture background thread.
105	    pub struct PttCaptureState {
106	        pub listening: bool,
107	        pub captured_key: Arc<Mutex<Option<String>>>,
108	        pub handle: Option<std::thread::JoinHandle<()>>,
109	        pub error: Option<String>,
110	    }
111	
112	    impl PttCaptureState {
113	        pub fn new() -> Self {
114	            Self {
115	                listening: false,
116	                captured_key: Arc::new(Mutex::new(None)),
117	                handle: None,
118	                error: None,
119	            }
120	        }
121	
122	        /// True when the thread has finished and deposited a key name.
123	        pub fn has_result(&self) -> bool {
124	            self.captured_key.lock().map(|g| g.is_some()).unwrap_or(false)
125	        }
126	
127	        /// Take the captured key name, leaving None in its place.
128	        pub fn take_result(&self) -> Option<String> {
129	            self.captured_key.lock().ok()?.take()
130	        }
131	    }
