140	
141	    /// Render the wizard panel for the current incomplete step.
142	    ///
143	    /// Returns an updated `FirstRunState` — call probe::run() after actions.
144	    /// If setup is complete, returns the current state unchanged.
145	    pub fn show_wizard(
146	        ui: &mut egui::Ui,
147	        state: &mut FirstRunState,
148	        ptt: &mut PttCaptureState,
149	        dl: &mut ModelDownloadState,
150	        uinput: &mut UinputSetupState,
151	        config_example_contents: &str,
152	        hd2_profile_contents: &str,
153	    ) {
154	        // Harvest PTT result from background thread if ready
155	        if ptt.listening && ptt.has_result() {
156	            if let Some(key_name) = ptt.take_result() {
157	                ptt.listening = false;
158	                match write_ptt_key_to_config(&key_name) {
159	                    Ok(()) => {
160	                        info!(key = %key_name, "PTT key written to config");
161	                        *state = probe::run();
162	                    }
163	                    Err(e) => {
164	                        error!(key = %key_name, reason = %e, "Failed to write PTT key to config");
165	                        ptt.error = Some(format!("Failed to save key: {e}"));
166	                    }
167	                }
168	            }
169	        }
170	
171	        // Reap finished thread handle to avoid leaking it
172	        if let Some(h) = &ptt.handle {
173	            if h.is_finished() {
174	                if let Some(handle) = ptt.handle.take() {
175	                    let _ = handle.join();
176	                }
177	            }
178	        }
179	
180	        // Re-probe after download completes, then reap the handle.
181	        if let Some(h) = &dl.handle {
182	            if h.is_finished() {
183	                if let Ok(DownloadStatus::Done) = dl.status.lock().map(|g| g.clone()) {
184	                    *state = probe::run();
185	                }
186	                if let Some(handle) = dl.handle.take() {
187	                    let _ = handle.join();
188	                }
189	            }
190	        }
191	
192	        // Harvest modprobe and usermod thread results.
193	        if let Some(h) = &uinput.modprobe_handle {
194	            if h.is_finished() {
195	                if let Some(handle) = uinput.modprobe_handle.take() {
196	                    uinput.modprobe = match handle.join() {
197	                        Ok(Ok(())) => SetupActionStatus::Done,
198	                        Ok(Err(e)) => SetupActionStatus::Failed(e),
199	                        Err(_) => SetupActionStatus::Failed("thread panicked".to_string()),
200	                    };
201	                    *state = probe::run();
202	                }
203	            }
204	        }
205	        if let Some(h) = &uinput.usermod_handle {
206	            if h.is_finished() {
207	                if let Some(handle) = uinput.usermod_handle.take() {
208	                    uinput.usermod = match handle.join() {
209	                        Ok(Ok(())) => SetupActionStatus::Done,
210	                        Ok(Err(e)) => SetupActionStatus::Failed(e),
211	                        Err(_) => SetupActionStatus::Failed("thread panicked".to_string()),
212	                    };
213	                    *state = probe::run();
214	                }
215	            }
216	        }
217	
218	        match state.first_incomplete_step() {
219	            None => {
220	                ui.heading("Setup complete");
221	                ui.label("All prerequisites satisfied. Loading config app…");
222	            }
223	            Some(SetupStep::CreateConfig) => {
224	                show_create_config(ui, state, config_example_contents, hd2_profile_contents);
225	            }
226	            Some(SetupStep::InstallModel) => {
227	                show_install_model(ui, state, dl);
228	            }
229	            Some(SetupStep::SetupUinput) => {
230	                show_setup_uinput(ui, state, uinput);
231	            }
232	            Some(SetupStep::ConfigurePtt) => {
233	                show_configure_ptt(ui, state, ptt);
234	            }
235	        }
236	    }
