377	    /// Download the model file to `dest`, streaming progress into `status`.
378	    fn download_model(status: Arc<Mutex<DownloadStatus>>, dest: &str) {
379	        info!(url = MODEL_URL, dest, "starting model download");
380	
381	        let dest_path = PathBuf::from(dest);
382	        if let Some(parent) = dest_path.parent() {
383	            if let Err(e) = std::fs::create_dir_all(parent) {
384	                error!(reason = %e, "failed to create model directory");
385	                if let Ok(mut g) = status.lock() {
386	                    *g = DownloadStatus::Failed(format!("mkdir failed: {e}"));
387	                }
388	                return;
389	            }
390	        }
391	
392	        let response = match ureq::get(MODEL_URL).call() {
393	            Ok(r) => r,
394	            Err(e) => {
395	                error!(reason = %e, "model download request failed");
396	                if let Ok(mut g) = status.lock() {
397	                    *g = DownloadStatus::Failed(e.to_string());
398	                }
399	                return;
400	            }
401	        };
402	
403	        let total = response
404	            .header("content-length")
405	            .and_then(|v| v.parse::<u64>().ok());
406	
407	        // Write to a temp file alongside the destination, then rename atomically.
408	        let tmp_path = dest_path.with_extension("tmp");
409	        let mut file = match std::fs::File::create(&tmp_path) {
410	            Ok(f) => f,
411	            Err(e) => {
412	                error!(reason = %e, "failed to create temp file");
413	                if let Ok(mut g) = status.lock() {
414	                    *g = DownloadStatus::Failed(format!("file create failed: {e}"));
415	                }
416	                return;
417	            }
418	        };
419	
420	        let mut reader = response.into_reader();
421	        let mut buf = vec![0u8; 65536];
422	        let mut received: u64 = 0;
423	
424	        loop {
425	            match reader.read(&mut buf) {
426	                Ok(0) => break,
427	                Ok(n) => {
428	                    use std::io::Write;
429	                    if let Err(e) = file.write_all(&buf[..n]) {
430	                        error!(reason = %e, "write error during download");
431	                        let _ = std::fs::remove_file(&tmp_path);
432	                        if let Ok(mut g) = status.lock() {
433	                            *g = DownloadStatus::Failed(format!("write error: {e}"));
434	                        }
435	                        return;
436	                    }
437	                    received += n as u64;
438	                    if let Ok(mut g) = status.lock() {
439	                        *g = DownloadStatus::Downloading { received, total };
440	                    }
441	                }
442	                Err(e) => {
443	                    error!(reason = %e, "read error during download");
444	                    let _ = std::fs::remove_file(&tmp_path);
445	                    if let Ok(mut g) = status.lock() {
446	                        *g = DownloadStatus::Failed(format!("read error: {e}"));
447	                    }
448	                    return;
449	                }
450	            }
451	        }
452	
453	        if let Err(e) = std::fs::rename(&tmp_path, &dest_path) {
454	            error!(reason = %e, "failed to rename tmp file");
455	            let _ = std::fs::remove_file(&tmp_path);
456	            if let Ok(mut g) = status.lock() {
457	                *g = DownloadStatus::Failed(format!("rename failed: {e}"));
458	            }
459	            return;
460	        }
461	
462	        info!(dest, bytes = received, "model download complete");
463	        if let Ok(mut g) = status.lock() {
464	            *g = DownloadStatus::Done;
465	        }
466	    }
