555	    /// Run a command via pkexec (polkit) and return Ok(()) on exit 0, Err(msg) otherwise.
556	    fn run_pkexec(args: &[&str]) -> Result<(), String> {
557	        let mut cmd_args = vec!["pkexec"];
558	        cmd_args.extend_from_slice(args);
559	
560	        let status = std::process::Command::new(cmd_args[0])
561	            .args(&cmd_args[1..])
562	            .status()
563	            .map_err(|e| format!("failed to run pkexec: {e}"))?;
564	
565	        if status.success() {
566	            Ok(())
567	        } else {
568	            Err(format!(
569	                "command exited with code {}",
570	                status.code().unwrap_or(-1)
571	            ))
572	        }
573	    }
