645	    // ── PTT capture thread ───────────────────────────────────────────────────
646	
647	    /// Open the first readable keyboard evdev device and wait for the first KeyDown event.
648	    /// Stores the key name in `captured` and returns.
649	    fn capture_first_keypress(captured: Arc<Mutex<Option<String>>>) {
650	        info!("PTT capture thread started");
651	
652	        let device = match find_keyboard_device() {
653	            Some(d) => d,
654	            None => {
655	                error!("PTT capture: no readable keyboard device found in /dev/input/event*");
656	                return;
657	            }
658	        };
659	
660	        info!(
661	            device = device.name().unwrap_or("unknown"),
662	            "PTT capture: using device"
663	        );
664	
665	        let mut device = device;
666	        loop {
667	            match device.fetch_events() {
668	                Ok(events) => {
669	                    for event in events {
670	                        if let EventSummary::Key(_, key, 1) = event.destructure() {
671	                            let name = format!("{key:?}");
672	                            info!(key = %name, "PTT capture: key pressed");
673	                            if let Ok(mut guard) = captured.lock() {
674	                                *guard = Some(name);
675	                            }
676	                            return;
677	                        }
678	                    }
679	                }
680	                Err(e) => {
681	                    error!(reason = %e, "PTT capture: device read error");
682	                    return;
683	                }
684	            }
685	        }
686	    }
687	
688	    fn find_keyboard_device() -> Option<Device> {
689	        // Prefer devices that report standard keyboard keys (KEY_A is a reliable indicator)
690	        for (_path, device) in evdev::enumerate() {
691	            if device
692	                .supported_keys()
693	                .is_some_and(|keys| keys.contains(evdev::KeyCode::KEY_A))
694	            {
695	                return Some(device);
696	            }
697	        }
698	        None
699	    }
700	
701	    // ── Config file write ────────────────────────────────────────────────────
702	
703	    /// Write `key: <key_name>` to the ptt section of the config file.
704	    ///
705	    /// Reads the existing config, replaces the ptt.key line if present,
706	    /// or appends a ptt section if the file has no ptt.key line.
707	    fn write_ptt_key_to_config(key_name: &str) -> std::io::Result<()> {
708	        let path = crate::ui::probe::config_path_for_display();
709	        let path = PathBuf::from(path);
710	
711	        let contents = std::fs::read_to_string(&path).unwrap_or_default();
712	        let new_contents = rewrite_ptt_key(&contents, key_name);
713	        std::fs::write(&path, new_contents)
714	    }
715	
716	    /// Pure function: rewrite config text to set ptt.key = key_name.
717	    ///
718	    /// If a `key: KEY_*` line already exists, replaces it.
719	    /// If a `# key:` commented line exists, replaces that.
720	    /// Otherwise appends a ptt block at the end.
721	    pub(crate) fn rewrite_ptt_key(config: &str, key_name: &str) -> String {
722	        let mut found = false;
723	        let mut lines: Vec<String> = config
724	            .lines()
725	            .map(|line| {
726	                let trimmed = line.trim();
727	                // Match existing key: line (active or commented)
728	                if !found
729	                    && (trimmed.starts_with("key:") || trimmed.starts_with("# key:"))
730	                    && trimmed.contains("KEY_")
731	                {
732	                    found = true;
733	                    // Preserve indentation
734	                    let indent = line.len() - line.trim_start().len();
735	                    format!("{}key: {key_name}", " ".repeat(indent))
736	                } else {
737	                    line.to_string()
738	                }
739	            })
740	            .collect();
741	
742	        if !found {
743	            lines.push(String::new());
744	            lines.push("ptt:".to_string());
745	            lines.push(format!("  key: {key_name}"));
746	        }
747	
748	        let mut result = lines.join("\n");
749	        if !result.ends_with('\n') {
750	            result.push('\n');
751	        }
752	        result
753	    }
754	}
755	
